-- -----------------------------------------------------
-- Table `hotel_management`.`clients`
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS `hotel_management`.`clients` (
  `client_id` INT UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '画面上の表記は「顧客コード」',
  `old_user_id` BIGINT NULL DEFAULT NULL,
  `login_id` VARCHAR(128) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL COMMENT 'フロント側からの登録時はＮＯＴ ＮＵＬＬ',
  `login_password` VARCHAR(256) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL COMMENT '暗号化した値。フロント側からの登録時はＮＯＴ ＮＵＬＬ',
  `data_status` TINYINT NOT NULL DEFAULT '1' COMMENT '0=利用停止、1=利用可能、2=非表示\\n利用停止:未来で使用する可能性がない\\n非表示：論理削除（参照できる必要あり）',
  `data_type` TINYINT NOT NULL COMMENT '0=指定なし、1=個人、2=法人、3=特別法人',
  `client_name` VARCHAR(256) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NOT NULL COMMENT '法人(data_type=2)の場合、「企業名」アルファベットは半角英字・小文字で格納',
  `client_name_kana` VARCHAR(256) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL COMMENT '法人(data_type=2)の場合、「企業名（カナ）」',
  `birthday` DATE NULL DEFAULT NULL COMMENT '法人(data_type=2)の場合、NULL許可',
  `type_calendal` TINYINT(1) NOT NULL DEFAULT '0',
  `sex` TINYINT NULL DEFAULT '9' COMMENT '1=男性、2=女性、9=不明\\n法人(data_type=2)の場合、「窓口担当者」の性別',
  `contact_name` VARCHAR(256) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `contact_name_kana` VARCHAR(256) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `company_name` VARCHAR(256) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `company_name_kana` VARCHAR(256) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `email` VARCHAR(256) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `zip_code` VARCHAR(9) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL COMMENT '桁数の切れ目（ハイフンが入る箇所）について\\n            https://www.busoken.com/blog/%E6%B5%B7%E5%A4%96%E3%81%AE%E9%83%B5%E4%BE%BF%E7%95%AA%E5%8F%B7%E4%BA%8B%E6%83%85-expb',
  `company_zip_code` VARCHAR(9) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL COMMENT '桁数の切れ目（ハイフンが入る箇所）について\\n            https://www.busoken.com/blog/%E6%B5%B7%E5%A4%96%E3%81%AE%E9%83%B5%E4%BE%BF%E7%95%AA%E5%8F%B7%E4%BA%8B%E6%83%85-expb',
  `country_id` INT UNSIGNED NULL DEFAULT NULL,
  `address1` VARCHAR(256) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL COMMENT '法人の場合、所在地（State/Province/Region）',
  `address2` VARCHAR(256) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL COMMENT '法人の場合、所在地（State/Province/Region）',
  `company_address1` VARCHAR(256) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL COMMENT '法人の場合、所在地（State/Province/Region）',
  `company_address2` VARCHAR(256) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL COMMENT '法人の場合、所在地（State/Province/Region）',
  `tel` VARCHAR(18) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL COMMENT '\"\"+\"\"を除いた12桁が最長。\"\"+\"\"や\"\"-\"\"で+3文字はあり得る。\\nhttps://ja.wikipedia.org/wiki/E.164\\n法人(data_type=2)の場合、「会社電話番号」',
  `tel_phone` VARCHAR(18) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL COMMENT '法人(data_type=2)の場合、「担当窓口の電話番号」',
  `tel_emergency` VARCHAR(18) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `company_tel` VARCHAR(16) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `emargency_relation` VARCHAR(256) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `fax` VARCHAR(18) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `postpaid_flag` TINYINT(1) NOT NULL DEFAULT '0' COMMENT '特別法人(data_type=3)の場合のみ1を設定可能',
  `stay_duration_auto_flag` TINYINT(1) NOT NULL DEFAULT '0' COMMENT '0=なし、1=あり',
  `used_messy_level` TINYINT NULL DEFAULT NULL COMMENT '0=無、1=普通、2=少、3=多',
  `ug_flag` TINYINT(1) NOT NULL DEFAULT '0' COMMENT '1=UG',
  `advertising_type` TINYINT NULL DEFAULT NULL,
  `memo` TEXT CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `use_count` SMALLINT NOT NULL COMMENT '予約の登録・更新・削除時にカウントし直す',
  `last_used_service_ids` TEXT CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL COMMENT '最後に利用したサービスのIDをカンマ区切りで結合した文字列で保存',
  `client_tag_ids` LONGTEXT CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_bin' NULL DEFAULT NULL,
  `department_name` VARCHAR(255) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `department_name_kana` VARCHAR(255) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `representative_name` VARCHAR(255) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `created_at` TIMESTAMP NULL DEFAULT NULL,
  `updated_at` TIMESTAMP NULL DEFAULT NULL,
  `deleted_at` TIMESTAMP NULL DEFAULT NULL,
  `created_staff_id` INT UNSIGNED NOT NULL,
  `updated_staff_id` INT UNSIGNED NULL DEFAULT NULL,
  `deleted_staff_id` INT UNSIGNED NULL DEFAULT NULL,
  PRIMARY KEY (`client_id`),
  UNIQUE INDEX `old_user_id` (`old_user_id` ASC) VISIBLE,
  INDEX `clients_created_staff_id_foreign` (`created_staff_id` ASC) VISIBLE,
  INDEX `clients_updated_staff_id_foreign` (`updated_staff_id` ASC) VISIBLE,
  INDEX `clients_deleted_staff_id_foreign` (`deleted_staff_id` ASC) VISIBLE,
  INDEX `clients_country_id_foreign` (`country_id` ASC) VISIBLE,
  INDEX `clients_client_id_index` (`client_id` ASC) VISIBLE,
  CONSTRAINT `clients_country_id_foreign`
    FOREIGN KEY (`country_id`)
    REFERENCES `hotel_management`.`countries` (`country_id`),
  CONSTRAINT `clients_created_staff_id_foreign`
    FOREIGN KEY (`created_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `clients_deleted_staff_id_foreign`
    FOREIGN KEY (`deleted_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `clients_updated_staff_id_foreign`
    FOREIGN KEY (`updated_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`))
ENGINE = InnoDB
AUTO_INCREMENT = 110773
DEFAULT CHARACTER SET = utf8mb4
COLLATE = utf8mb4_unicode_ci;


-- -----------------------------------------------------
