  CONSTRAINT `keyboxes_created_staff_id_foreign`
    FOREIGN KEY (`created_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `keyboxes_deleted_staff_id_foreign`
    FOREIGN KEY (`deleted_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `keyboxes_last_reserve_id_foreign`
    FOREIGN KEY (`last_reserve_id`)
    REFERENCES `hotel_management`.`reserves` (`reserve_id`),
  CONSTRAINT `keyboxes_updated_staff_id_foreign`
    FOREIGN KEY (`updated_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`))
ENGINE = InnoDB
AUTO_INCREMENT = 2416
DEFAULT CHARACTER SET = utf8mb4
COLLATE = utf8mb4_unicode_ci;


