CREATE TABLE IF NOT EXISTS `hotel_management`.`stay_types` (
  `stay_type_id` INT UNSIGNED NOT NULL AUTO_INCREMENT,
  `stay_contract_type_id` TINYINT NOT NULL DEFAULT '1' COMMENT '1=ウィークリー契約、2=マンスリー契約',
  `stay_type_name` VARCHAR(64) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NOT NULL COMMENT '1～6泊、7～1ヶ月未満、1～3ヶ月未満、3～7ヶ月未満、7ヶ月以上',
  `stay_type_name_en` VARCHAR(128) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NOT NULL,
  `stay_type_name_short` VARCHAR(4) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NOT NULL,
  `order_num` SMALLINT NOT NULL DEFAULT '99',
  `active` TINYINT(1) NOT NULL DEFAULT '1' COMMENT '削除の有無が不明なので「データ状態」にしないでおく',
  `created_at` TIMESTAMP NULL DEFAULT NULL,
  `updated_at` TIMESTAMP NULL DEFAULT NULL,
  `deleted_at` TIMESTAMP NULL DEFAULT NULL,
  `created_staff_id` INT UNSIGNED NOT NULL,
  `updated_staff_id` INT UNSIGNED NULL DEFAULT NULL,
  `deleted_staff_id` INT UNSIGNED NULL DEFAULT NULL,
  PRIMARY KEY (`stay_type_id`),
  INDEX `stay_types_created_staff_id_foreign` (`created_staff_id` ASC) VISIBLE,
  INDEX `stay_types_updated_staff_id_foreign` (`updated_staff_id` ASC) VISIBLE,
  INDEX `stay_types_deleted_staff_id_foreign` (`deleted_staff_id` ASC) VISIBLE,
  INDEX `stay_types_stay_type_id_index` (`stay_type_id` ASC) VISIBLE,
  CONSTRAINT `stay_types_created_staff_id_foreign`
    FOREIGN KEY (`created_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `stay_types_deleted_staff_id_foreign`
    FOREIGN KEY (`deleted_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `stay_types_updated_staff_id_foreign`
    FOREIGN KEY (`updated_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`))
ENGINE = InnoDB
AUTO_INCREMENT = 8
DEFAULT CHARACTER SET = utf8mb4
COLLATE = utf8mb4_unicode_ci;


-- -----------------------------------------------------
-- Table `hotel_management`.`reserves`
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS `hotel_management`.`reserves` (
  `reserve_id` INT UNSIGNED NOT NULL AUTO_INCREMENT,
  `parent_reserve_id` INT UNSIGNED NULL DEFAULT NULL,
  `old_id` VARCHAR(512) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `client_id` INT UNSIGNED NULL DEFAULT NULL,
  `stay_type_id` INT UNSIGNED NULL DEFAULT NULL,
  `data_status` TINYINT NOT NULL DEFAULT '1' COMMENT '0=利用停止、1=利用可能、2=非表示\\n            利用停止:未来で使用する可能性がない\\n            非表示：論理削除（参照できる必要あり）',
  `rakuten_flag` TINYINT(1) NOT NULL DEFAULT '0',
  `rakuten_room_plan_id` INT UNSIGNED NULL DEFAULT NULL,
  `draft_flag` TINYINT(1) NOT NULL DEFAULT '0',
  `memo_flag` TINYINT(1) NOT NULL DEFAULT '0',
  `eternity_draft` TINYINT(1) NOT NULL DEFAULT '0',
  `has_seen` TINYINT(1) NOT NULL DEFAULT '0',
  `expired_date` TINYINT NULL DEFAULT NULL,
  `reserve_type` SMALLINT NULL DEFAULT NULL COMMENT '1=国内、2=英語',
  `delete_status` TINYINT NULL DEFAULT NULL COMMENT 'NULL=削除ではない、1=削除、2=キャンセル、3=No-Show',
  `noreserve_count_before` SMALLINT NULL DEFAULT NULL,
  `period_from` DATETIME NULL DEFAULT NULL COMMENT '移動前も移動後も含めた期間（時刻は\"入居時間\"）',
  `period_to` DATETIME NULL DEFAULT NULL COMMENT '同上',
  `original_period_from` DATETIME NULL DEFAULT NULL,
  `original_period_to` DATETIME NULL DEFAULT NULL,
  `original_flag` TINYINT(1) NOT NULL DEFAULT '0',
  `period_type` VARCHAR(32) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `period_before` DATETIME NULL DEFAULT NULL COMMENT '早期退室や延長される前の日時',
  `noreserve_count_after` SMALLINT NULL DEFAULT NULL,
  `auto_extend_flag` TINYINT(1) NOT NULL DEFAULT '0',
  `confirm_flag` TINYINT(1) NOT NULL DEFAULT '1' COMMENT 'FALSE=未定(仮予約)、TRUE=確定',
  `early_exit_datetime` DATETIME NULL DEFAULT NULL,
  `time_extend_num` SMALLINT NULL DEFAULT NULL,
  `moved_facility_id` INT UNSIGNED NULL DEFAULT NULL,
  `moved_room_id` INT UNSIGNED NULL DEFAULT NULL,
  `rental_keys` TINYINT NULL DEFAULT NULL,
  `return_keys` TINYINT NULL DEFAULT NULL,
  `amendment` VARCHAR(128) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `deposit` INT NULL DEFAULT NULL,
  `extension_time` SMALLINT NULL DEFAULT NULL,
  `note` VARCHAR(256) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `overdue_debt_note` TEXT CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `booking_unit_price` INT NULL DEFAULT NULL,
  `adjustment_unit_price` INT NULL DEFAULT NULL,
  `campaign_price_flag` TINYINT(1) NOT NULL DEFAULT '0',
  `checkin_flag` INT UNSIGNED NOT NULL DEFAULT '0',
  `checked_in_at` DATETIME NULL DEFAULT NULL,
  `directcheckin_flag` TINYINT(1) NOT NULL DEFAULT '0',
  `directcheckin_type` SMALLINT NULL DEFAULT NULL COMMENT '1 = 来店、2 = 6ビル、3 = D/I、4 = YCAT、5 = 部屋届け',
  `box_usage_period_type` SMALLINT NULL DEFAULT NULL,
  `box_usage_start_date` DATE NULL DEFAULT NULL,
  `box_usage_end_date` DATE NULL DEFAULT NULL,
  `keybox_id` INT UNSIGNED NULL DEFAULT NULL,
  `keybox_password` VARCHAR(32) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL COMMENT 'D/I時に使用',
  `charge_staff_id` INT UNSIGNED NULL DEFAULT NULL COMMENT 'D/I時に使用',
  `charge_staff_id2` INT UNSIGNED NULL DEFAULT NULL,
  `checkin_receptionist_id` INT UNSIGNED NULL DEFAULT NULL,
  `di_contact_staff_id` INT UNSIGNED NULL DEFAULT NULL,
  `checkout_receptionist_id` INT UNSIGNED NULL DEFAULT NULL,
  `checkout_receptionist_id_2` INT UNSIGNED NULL DEFAULT NULL,
  `confirm_staff_id` INT UNSIGNED NULL DEFAULT NULL,
  `contacted_flag` TINYINT(1) NULL DEFAULT NULL COMMENT 'D/I時に使用',
  `directcheckin_note` VARCHAR(256) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL COMMENT 'D/I時に使用',
  `advertising_type` TINYINT NULL DEFAULT NULL COMMENT '1=リピート、2=WI (ウォークイン)、3=HP、4=楽天、5=英語サイト、9=その他',
  `substitute_reserve_id` INT UNSIGNED NULL DEFAULT NULL,
  `substitute_facility_id` INT UNSIGNED NULL DEFAULT NULL,
  `substitute_room_id` INT UNSIGNED NULL DEFAULT NULL,
  `substitute_room_to` DATETIME NULL DEFAULT NULL,
  `substitute_room_from` DATETIME NULL DEFAULT NULL,
  `substitute_room_note` VARCHAR(1024) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `key_return_contact_type` TINYINT NULL DEFAULT NULL COMMENT '1=持参, 2=TEL, 3=早期退出',
  `key_return_flag` TINYINT(1) NULL DEFAULT NULL,
  `check_keys_datetime` DATE NULL DEFAULT NULL,
  `key_return_datetime` DATETIME NULL DEFAULT NULL,
  `last_stay_date` DATETIME NULL DEFAULT NULL,
  `checkin_date` DATETIME NULL DEFAULT NULL,
  `payment_due_date` DATETIME NULL DEFAULT NULL,
  `pet_flag` TINYINT(1) NOT NULL DEFAULT '0',
  `dog_count` SMALLINT NULL DEFAULT NULL,
  `cat_count` SMALLINT NULL DEFAULT NULL,
  `other_count` SMALLINT NULL DEFAULT NULL,
  `pet_note` VARCHAR(256) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `futon_flag` TINYINT(1) NOT NULL DEFAULT '0',
  `deliverybox_flag` TINYINT(1) NOT NULL DEFAULT '0',
  `deliverybox_card_number` VARCHAR(16) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `survey_answer` TEXT CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `announcement` VARCHAR(1024) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `present_flag` TINYINT(1) NULL DEFAULT '0',
  `present_delivery_date` DATE NULL DEFAULT NULL,
  `notice_comment` VARCHAR(1024) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `request_announcement` VARCHAR(1024) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `sale_announcement` VARCHAR(1024) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `disable_reservation` TINYINT(1) NOT NULL DEFAULT '0',
  `pre_delivery_key_flag` TINYINT(1) NOT NULL DEFAULT '0',
  `room_dirty_level` TINYINT NULL DEFAULT NULL,
  `created_at` TIMESTAMP NULL DEFAULT NULL,
  `updated_at` TIMESTAMP NULL DEFAULT NULL,
  `deleted_at` TIMESTAMP NULL DEFAULT NULL,
  `created_staff_id` INT UNSIGNED NOT NULL,
  `updated_staff_id` INT UNSIGNED NULL DEFAULT NULL,
  `deleted_staff_id` INT UNSIGNED NULL DEFAULT NULL,
  `is_key_in_completed` TINYINT(1) NOT NULL DEFAULT '0',
  `skip_mismatch_parking_popup` TINYINT(1) NOT NULL DEFAULT '0',
  PRIMARY KEY (`reserve_id`),
  INDEX `reserves_created_staff_id_foreign` (`created_staff_id` ASC) VISIBLE,
  INDEX `reserves_updated_staff_id_foreign` (`updated_staff_id` ASC) VISIBLE,
  INDEX `reserves_deleted_staff_id_foreign` (`deleted_staff_id` ASC) VISIBLE,
  INDEX `reserves_client_id_foreign` (`client_id` ASC) VISIBLE,
  INDEX `reserves_stay_type_id_foreign` (`stay_type_id` ASC) VISIBLE,
  INDEX `reserves_moved_facility_id_foreign` (`moved_facility_id` ASC) VISIBLE,
  INDEX `reserves_moved_room_id_foreign` (`moved_room_id` ASC) VISIBLE,
  INDEX `reserves_charge_staff_id_foreign` (`charge_staff_id` ASC) VISIBLE,
  INDEX `reserves_substitute_room_id_foreign` (`substitute_room_id` ASC) VISIBLE,
  INDEX `reserves_reserve_id_index` (`reserve_id` ASC) VISIBLE,
  INDEX `reserves_keybox_id_foreign` (`keybox_id` ASC) VISIBLE,
  INDEX `reserves_checkin_receptionist_id_foreign` (`checkin_receptionist_id` ASC) VISIBLE,
  INDEX `reserves_di_contact_staff_id_foreign` (`di_contact_staff_id` ASC) VISIBLE,
  INDEX `reserves_checkout_receptionist_id_foreign` (`checkout_receptionist_id` ASC) VISIBLE,
  INDEX `reserves_substitute_reserve_id_foreign` (`substitute_reserve_id` ASC) VISIBLE,
  INDEX `reserves_substitute_facility_id_foreign` (`substitute_facility_id` ASC) VISIBLE,
  INDEX `reserves_confirm_staff_id_foreign` (`confirm_staff_id` ASC) VISIBLE,
  INDEX `reserves_charge_staff_id2_foreign` (`charge_staff_id2` ASC) VISIBLE,
  INDEX `reserves_checkout_receptionist_id_2_foreign` (`checkout_receptionist_id_2` ASC) VISIBLE,
  INDEX `reserves_rakuten_room_plan_id_foreign` (`rakuten_room_plan_id` ASC) VISIBLE,
  CONSTRAINT `reserves_charge_staff_id2_foreign`
    FOREIGN KEY (`charge_staff_id2`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `reserves_charge_staff_id_foreign`
    FOREIGN KEY (`charge_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `reserves_checkin_receptionist_id_foreign`
    FOREIGN KEY (`checkin_receptionist_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `reserves_checkout_receptionist_id_2_foreign`
    FOREIGN KEY (`checkout_receptionist_id_2`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `reserves_checkout_receptionist_id_foreign`
    FOREIGN KEY (`checkout_receptionist_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `reserves_client_id_foreign`
    FOREIGN KEY (`client_id`)
    REFERENCES `hotel_management`.`clients` (`client_id`),
  CONSTRAINT `reserves_confirm_staff_id_foreign`
    FOREIGN KEY (`confirm_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `reserves_created_staff_id_foreign`
    FOREIGN KEY (`created_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `reserves_deleted_staff_id_foreign`
    FOREIGN KEY (`deleted_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `reserves_di_contact_staff_id_foreign`
    FOREIGN KEY (`di_contact_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `reserves_keybox_id_foreign`
    FOREIGN KEY (`keybox_id`)
    REFERENCES `hotel_management`.`keyboxes` (`keybox_id`),
  CONSTRAINT `reserves_moved_facility_id_foreign`
    FOREIGN KEY (`moved_facility_id`)
    REFERENCES `hotel_management`.`facilities` (`facility_id`),
  CONSTRAINT `reserves_moved_room_id_foreign`
    FOREIGN KEY (`moved_room_id`)
    REFERENCES `hotel_management`.`rooms` (`room_id`),
  CONSTRAINT `reserves_rakuten_room_plan_id_foreign`
    FOREIGN KEY (`rakuten_room_plan_id`)
    REFERENCES `hotel_management`.`rakuten_room_plans` (`id`),
  CONSTRAINT `reserves_stay_type_id_foreign`
