-- -----------------------------------------------------
-- Table `hotel_management`.`arranges`
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS `hotel_management`.`arranges` (
  `arrange_id` INT UNSIGNED NOT NULL AUTO_INCREMENT,
  `reserve_id` INT UNSIGNED NOT NULL,
  `data_status` TINYINT NOT NULL DEFAULT '1' COMMENT '0=利用停止、1=利用可能、2=非表示\\n            利用停止:未来で使用する可能性がない\\n            非表示：論理削除（参照できる必要あり）',
  `facility_id` INT UNSIGNED NOT NULL,
  `room_id` INT UNSIGNED NOT NULL,
  `content` TEXT CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NOT NULL,
  `absence_ok_flag` TINYINT(1) NOT NULL DEFAULT '0' COMMENT '不在時の可否。TRUE=可、FALSE=不可',
  `complete_flag` TINYINT(1) NOT NULL DEFAULT '0' COMMENT 'TRUE=対応済み、FALSE=未対応',
  `charge_staff_id` INT UNSIGNED NULL DEFAULT NULL,
  `charge_staff_id2` INT UNSIGNED NULL DEFAULT NULL,
  `arranging_date` DATETIME NOT NULL,
  `is_copy` TINYINT(1) NOT NULL DEFAULT '0',
  `is_copied_from_previous_day` TINYINT(1) NOT NULL DEFAULT '0',
  `created_at` TIMESTAMP NULL DEFAULT NULL,
  `updated_at` TIMESTAMP NULL DEFAULT NULL,
  `deleted_at` TIMESTAMP NULL DEFAULT NULL,
  `created_staff_id` INT UNSIGNED NOT NULL,
  `updated_staff_id` INT UNSIGNED NULL DEFAULT NULL,
  `deleted_staff_id` INT UNSIGNED NULL DEFAULT NULL,
  PRIMARY KEY (`arrange_id`),
  INDEX `arranges_created_staff_id_foreign` (`created_staff_id` ASC) VISIBLE,
  INDEX `arranges_updated_staff_id_foreign` (`updated_staff_id` ASC) VISIBLE,
  INDEX `arranges_deleted_staff_id_foreign` (`deleted_staff_id` ASC) VISIBLE,
  INDEX `arranges_reserve_id_foreign` (`reserve_id` ASC) VISIBLE,
  INDEX `arranges_facility_id_foreign` (`facility_id` ASC) VISIBLE,
  INDEX `arranges_room_id_foreign` (`room_id` ASC) VISIBLE,
  INDEX `arranges_arrange_id_index` (`arrange_id` ASC) VISIBLE,
  INDEX `arranges_charge_staff_id_foreign` (`charge_staff_id` ASC) VISIBLE,
  INDEX `arranges_charge_staff_id2_foreign` (`charge_staff_id2` ASC) VISIBLE,
  CONSTRAINT `arranges_charge_staff_id2_foreign`
    FOREIGN KEY (`charge_staff_id2`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `arranges_charge_staff_id_foreign`
    FOREIGN KEY (`charge_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `arranges_created_staff_id_foreign`
    FOREIGN KEY (`created_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `arranges_deleted_staff_id_foreign`
    FOREIGN KEY (`deleted_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `arranges_facility_id_foreign`
    FOREIGN KEY (`facility_id`)
    REFERENCES `hotel_management`.`facilities` (`facility_id`),
  CONSTRAINT `arranges_reserve_id_foreign`
    FOREIGN KEY (`reserve_id`)
    REFERENCES `hotel_management`.`reserves` (`reserve_id`),
  CONSTRAINT `arranges_room_id_foreign`
    FOREIGN KEY (`room_id`)
    REFERENCES `hotel_management`.`rooms` (`room_id`),
  CONSTRAINT `arranges_updated_staff_id_foreign`
    FOREIGN KEY (`updated_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`))
ENGINE = InnoDB
AUTO_INCREMENT = 243
DEFAULT CHARACTER SET = utf8mb4
COLLATE = utf8mb4_unicode_ci;


-- -----------------------------------------------------
-- Table `hotel_management`.`attendances`
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS `hotel_management`.`attendances` (
