  INDEX `bicycle_parking_reserves_stay_type_id_foreign` (`stay_type_id` ASC) VISIBLE,
  INDEX `bicycle_parking_reserves_bicycle_parking_id_foreign` (`bicycle_parking_id` ASC) VISIBLE,
  INDEX `bicycle_parking_reserves_bicycle_parking_reserve_id_index` (`bicycle_parking_reserve_id` ASC) VISIBLE,
  CONSTRAINT `bicycle_parking_reserves_bicycle_parking_id_foreign`
    FOREIGN KEY (`bicycle_parking_id`)
    REFERENCES `hotel_management`.`bicycle_parkings` (`bicycle_parking_id`),
