-- -----------------------------------------------------
-- Table `hotel_management`.`usage_statuses`
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS `hotel_management`.`usage_statuses` (
  `usage_status_id` INT UNSIGNED NOT NULL AUTO_INCREMENT,
  `reserve_id` INT UNSIGNED NULL DEFAULT NULL COMMENT '予約ID、内見ID、修繕・工事IDのいずれかは必須',
  `preview_id` INT UNSIGNED NULL DEFAULT NULL,
  `construction_id` INT UNSIGNED NULL DEFAULT NULL,
  `area_id` INT UNSIGNED NOT NULL,
  `facility_id` INT UNSIGNED NULL DEFAULT NULL COMMENT '工事が施設に対して行われるケースがあるため保持',
  `room_id` INT UNSIGNED NULL DEFAULT NULL,
  `data_status` TINYINT NOT NULL DEFAULT '1' COMMENT '0=利用停止、1=利用可能、2=非表示\\n利用停止:未来で使用する可能性がない\\n非表示：論理削除（参照できる必要あり）',
  `target` VARCHAR(32) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NOT NULL,
  `period_from` DATETIME NULL DEFAULT NULL COMMENT '予約で移動が発生した場合、それぞれの部屋での期間',
  `period_to` DATETIME NULL DEFAULT NULL COMMENT '予約で移動が発生した場合、それぞれの部屋での期間',
  `reserve_status` TINYINT NOT NULL COMMENT '1=確定(黄)、2=マンスリー(赤)、3=未確定、4=英語サイト',
  `substitute_flag` TINYINT(1) NOT NULL,
  `room_moved_flag` TINYINT(1) NOT NULL DEFAULT '0' COMMENT 'TRUE=移動あり',
  `direct_checkin_flag` TINYINT(1) NOT NULL DEFAULT '0' COMMENT 'TRUE=ダイレクトチェックイン',
  `campaign_price_flag` TINYINT(1) NOT NULL DEFAULT '0' COMMENT 'TRUE=キャンペーン価格',
  `extension_flag` TINYINT(1) NOT NULL,
  `note` TEXT CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NOT NULL COMMENT '「代替え設定＞内容」など',
  `created_at` TIMESTAMP NULL DEFAULT NULL,
  `updated_at` TIMESTAMP NULL DEFAULT NULL,
  `deleted_at` TIMESTAMP NULL DEFAULT NULL,
  `created_staff_id` INT UNSIGNED NOT NULL,
  `updated_staff_id` INT UNSIGNED NULL DEFAULT NULL,
  `deleted_staff_id` INT UNSIGNED NULL DEFAULT NULL,
  PRIMARY KEY (`usage_status_id`),
  INDEX `usage_statuses_created_staff_id_foreign` (`created_staff_id` ASC) VISIBLE,
  INDEX `usage_statuses_updated_staff_id_foreign` (`updated_staff_id` ASC) VISIBLE,
  INDEX `usage_statuses_deleted_staff_id_foreign` (`deleted_staff_id` ASC) VISIBLE,
  INDEX `usage_statuses_reserve_id_foreign` (`reserve_id` ASC) VISIBLE,
  INDEX `usage_statuses_preview_id_foreign` (`preview_id` ASC) VISIBLE,
  INDEX `usage_statuses_area_id_foreign` (`area_id` ASC) VISIBLE,
  INDEX `usage_statuses_facility_id_foreign` (`facility_id` ASC) VISIBLE,
  INDEX `usage_statuses_room_id_foreign` (`room_id` ASC) VISIBLE,
  INDEX `usage_statuses_usage_status_id_index` (`usage_status_id` ASC) VISIBLE,
  INDEX `usage_statuses_construction_id_foreign` (`construction_id` ASC) VISIBLE,
  CONSTRAINT `usage_statuses_area_id_foreign`
    FOREIGN KEY (`area_id`)
    REFERENCES `hotel_management`.`areas` (`area_id`),
  CONSTRAINT `usage_statuses_construction_id_foreign`
    FOREIGN KEY (`construction_id`)
    REFERENCES `hotel_management`.`constructions` (`construction_id`),
  CONSTRAINT `usage_statuses_created_staff_id_foreign`
    FOREIGN KEY (`created_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `usage_statuses_deleted_staff_id_foreign`
    FOREIGN KEY (`deleted_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `usage_statuses_facility_id_foreign`
    FOREIGN KEY (`facility_id`)
    REFERENCES `hotel_management`.`facilities` (`facility_id`),
  CONSTRAINT `usage_statuses_preview_id_foreign`
    FOREIGN KEY (`preview_id`)
    REFERENCES `hotel_management`.`previews` (`preview_id`),
  CONSTRAINT `usage_statuses_reserve_id_foreign`
    FOREIGN KEY (`reserve_id`)
    REFERENCES `hotel_management`.`reserves` (`reserve_id`),
  CONSTRAINT `usage_statuses_room_id_foreign`
    FOREIGN KEY (`room_id`)
    REFERENCES `hotel_management`.`rooms` (`room_id`),
  CONSTRAINT `usage_statuses_updated_staff_id_foreign`
    FOREIGN KEY (`updated_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`))
ENGINE = InnoDB
AUTO_INCREMENT = 196848
DEFAULT CHARACTER SET = utf8mb4
COLLATE = utf8mb4_unicode_ci;


-- -----------------------------------------------------
-- Table `hotel_management`.`cleaning_details`
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS `hotel_management`.`cleaning_details` (
  `cleaning_detail_id` INT UNSIGNED NOT NULL AUTO_INCREMENT,
  `parent_id` INT NULL DEFAULT NULL,
  `clean_id` INT UNSIGNED NULL DEFAULT NULL,
  `facility_id` INT UNSIGNED NOT NULL,
  `after_flag` TINYINT(1) NOT NULL DEFAULT '0' COMMENT 'TRUE=不要（翌日以降に再度リストアップする必要あり）',
  `cant_edit` TINYINT(1) NOT NULL DEFAULT '0',
  `is_hide` TINYINT(1) NOT NULL DEFAULT '0',
  `is_copy` TINYINT(1) NOT NULL DEFAULT '0',
  `is_copied_from_previous_day` TINYINT(1) NOT NULL DEFAULT '0',
  `change_flag` TINYINT(1) NOT NULL DEFAULT '0',
  `data_status` TINYINT NOT NULL DEFAULT '1' COMMENT '0=利用停止、1=利用可能、2=非表示\\n            利用停止:未来で使用する可能性がない\\n            非表示：論理削除（参照できる必要あり）',
  `data_type` TINYINT NOT NULL COMMENT '1=部屋清掃、2=共用部清掃、3=鍵回収・安全確認、4=フィットネスジム除菌清掃',
  `room_id` INT UNSIGNED NULL DEFAULT NULL,
  `reserve_id` INT UNSIGNED NULL DEFAULT NULL,
  `usage_status_id` INT UNSIGNED NULL DEFAULT NULL,
  `other_target` VARCHAR(512) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL COMMENT '部屋以外(共用部清掃など)の場合に記載',
  `main_staff_id` INT UNSIGNED NULL DEFAULT NULL,
  `sub_staff_id` INT UNSIGNED NULL DEFAULT NULL,
  `check_staff_id` INT UNSIGNED NULL DEFAULT NULL,
  `main_staff_external_flag` TINYINT(1) NOT NULL DEFAULT '0',
  `sub_staff_external_flag` TINYINT(1) NOT NULL DEFAULT '0',
  `check_staff_external_flag` TINYINT(1) NOT NULL DEFAULT '0',
  `start_datetime` DATETIME NULL DEFAULT NULL,
  `end_datetime` DATETIME NULL DEFAULT NULL,
  `finish_datetime` DATETIME NULL DEFAULT NULL,
  `scheduled_date` DATE NULL DEFAULT NULL,
  `copied_scheduled_date` DATE NULL DEFAULT NULL,
  `check_safety_flag` TINYINT NULL DEFAULT '0',
  `check_safety_datetime` DATETIME NULL DEFAULT NULL,
  `use_key_type` TINYINT NOT NULL DEFAULT '1',
  `clean_status` TINYINT NULL DEFAULT '1' COMMENT '1=清掃全残、2=清掃残り、3=仕上残り、4=清掃中、5=清掃済(未確認)、6=清掃済(確認済)',
  `order_num` SMALLINT NOT NULL DEFAULT '1',
  `comment` TEXT CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `report_img1` VARCHAR(512) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `report_img2` VARCHAR(512) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `report_img3` VARCHAR(512) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `report_img4` VARCHAR(512) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `buiding` VARCHAR(255) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `cleaning_area` VARCHAR(255) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `created_at` TIMESTAMP NULL DEFAULT NULL,
  `updated_at` TIMESTAMP NULL DEFAULT NULL,
  `deleted_at` TIMESTAMP NULL DEFAULT NULL,
  `created_staff_id` INT UNSIGNED NOT NULL,
  `updated_staff_id` INT UNSIGNED NULL DEFAULT NULL,
  `deleted_staff_id` INT UNSIGNED NULL DEFAULT NULL,
  PRIMARY KEY (`cleaning_detail_id`),
  INDEX `cleaning_details_created_staff_id_foreign` (`created_staff_id` ASC) VISIBLE,
  INDEX `cleaning_details_updated_staff_id_foreign` (`updated_staff_id` ASC) VISIBLE,
  INDEX `cleaning_details_deleted_staff_id_foreign` (`deleted_staff_id` ASC) VISIBLE,
  INDEX `cleaning_details_facility_id_foreign` (`facility_id` ASC) VISIBLE,
  INDEX `cleaning_details_room_id_foreign` (`room_id` ASC) VISIBLE,
  INDEX `cleaning_details_usage_status_id_foreign` (`usage_status_id` ASC) VISIBLE,
  INDEX `cleaning_details_main_staff_id_foreign` (`main_staff_id` ASC) VISIBLE,
  INDEX `cleaning_details_sub_staff_id_foreign` (`sub_staff_id` ASC) VISIBLE,
  INDEX `cleaning_details_check_staff_id_foreign` (`check_staff_id` ASC) VISIBLE,
  INDEX `cleaning_details_cleaning_detail_id_index` (`cleaning_detail_id` ASC) VISIBLE,
  INDEX `cleaning_details_clean_id_foreign` (`clean_id` ASC) VISIBLE,
  INDEX `cleaning_details_reserve_id_foreign` (`reserve_id` ASC) VISIBLE,
  CONSTRAINT `cleaning_details_check_staff_id_foreign`
    FOREIGN KEY (`check_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `cleaning_details_clean_id_foreign`
    FOREIGN KEY (`clean_id`)
    REFERENCES `hotel_management`.`cleans` (`clean_id`),
  CONSTRAINT `cleaning_details_created_staff_id_foreign`
    FOREIGN KEY (`created_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `cleaning_details_deleted_staff_id_foreign`
    FOREIGN KEY (`deleted_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `cleaning_details_facility_id_foreign`
    FOREIGN KEY (`facility_id`)
