  CONSTRAINT `cleaning_details_sub_staff_id_foreign`
    FOREIGN KEY (`sub_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `cleaning_details_updated_staff_id_foreign`
    FOREIGN KEY (`updated_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `cleaning_details_usage_status_id_foreign`
    FOREIGN KEY (`usage_status_id`)
    REFERENCES `hotel_management`.`usage_statuses` (`usage_status_id`))
ENGINE = InnoDB
AUTO_INCREMENT = 72406
DEFAULT CHARACTER SET = utf8mb4
COLLATE = utf8mb4_unicode_ci;


