  CONSTRAINT `identifications_updated_staff_id_foreign`
    FOREIGN KEY (`updated_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`))
ENGINE = InnoDB
AUTO_INCREMENT = 17811
DEFAULT CHARACTER SET = utf8mb4
