-- -----------------------------------------------------
-- Table `hotel_management`.`occupiers`
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS `hotel_management`.`occupiers` (
  `occupier_id` INT UNSIGNED NOT NULL AUTO_INCREMENT,
  `parent_client_id` INT UNSIGNED NOT NULL,
  `data_status` TINYINT NOT NULL DEFAULT '1' COMMENT '0=利用停止、1=利用可能、2=非表示\\n利用停止:未来で使用する可能性がない\\n非表示：論理削除（参照できる必要あり）',
  `title_prefix` VARCHAR(255) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `client_name` VARCHAR(128) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL COMMENT 'アルファベットは半角英字・小文字で格納',
  `title_suffix` VARCHAR(255) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `client_name_kana` VARCHAR(128) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `birthday` DATE NULL DEFAULT NULL,
  `sex` TINYINT NULL DEFAULT '9' COMMENT '1=男性、2=女性、9=不明\\n            法人(data_type=2)の場合、「窓口担当者」の性別',
  `zip_code` VARCHAR(9) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL COMMENT '桁数の切れ目（ハイフンが入る箇所）について\\n            https://www.busoken.com/blog/%E6%B5%B7%E5%A4%96%E3%81%AE%E9%83%B5%E4%BE%BF%E7%95%AA%E5%8F%B7%E4%BA%8B%E6%83%85-expb',
  `address1` VARCHAR(256) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL COMMENT '法人の場合、所在地（State/Province/Region）',
  `address2` VARCHAR(256) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL COMMENT '法人の場合、所在地（State/Province/Region）',
  `tel` VARCHAR(18) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL COMMENT '\"\"+\"\"を除いた12桁が最長。\"\"+\"\"や\"\"-\"\"で+3文字はあり得る。\\nhttps://ja.wikipedia.org/wiki/E.164\\n法人(data_type=2)の場合、「会社電話番号」',
  `ug_flag` TINYINT(1) NOT NULL DEFAULT '0',
  `created_at` TIMESTAMP NULL DEFAULT NULL,
  `updated_at` TIMESTAMP NULL DEFAULT NULL,
  `deleted_at` TIMESTAMP NULL DEFAULT NULL,
  `created_staff_id` INT UNSIGNED NOT NULL,
  `updated_staff_id` INT UNSIGNED NULL DEFAULT NULL,
  `deleted_staff_id` INT UNSIGNED NULL DEFAULT NULL,
  PRIMARY KEY (`occupier_id`),
  INDEX `occupiers_created_staff_id_foreign` (`created_staff_id` ASC) VISIBLE,
  INDEX `occupiers_updated_staff_id_foreign` (`updated_staff_id` ASC) VISIBLE,
  INDEX `occupiers_deleted_staff_id_foreign` (`deleted_staff_id` ASC) VISIBLE,
  INDEX `occupiers_parent_client_id_foreign` (`parent_client_id` ASC) VISIBLE,
  INDEX `occupiers_occupier_id_index` (`occupier_id` ASC) VISIBLE,
  CONSTRAINT `occupiers_created_staff_id_foreign`
    FOREIGN KEY (`created_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `occupiers_deleted_staff_id_foreign`
    FOREIGN KEY (`deleted_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`),
  CONSTRAINT `occupiers_parent_client_id_foreign`
    FOREIGN KEY (`parent_client_id`)
    REFERENCES `hotel_management`.`clients` (`client_id`),
  CONSTRAINT `occupiers_updated_staff_id_foreign`
    FOREIGN KEY (`updated_staff_id`)
    REFERENCES `hotel_management`.`staffs` (`staff_id`))
ENGINE = InnoDB
AUTO_INCREMENT = 6466
DEFAULT CHARACTER SET = utf8mb4
COLLATE = utf8mb4_unicode_ci;


