-- -----------------------------------------------------
-- Table `hotel_management`.`parking_reserves`
-- -----------------------------------------------------
CREATE TABLE IF NOT EXISTS `hotel_management`.`parking_reserves` (
  `parking_reserve_id` INT UNSIGNED NOT NULL AUTO_INCREMENT,
  `reserve_id` INT UNSIGNED NULL DEFAULT NULL,
  `client_id` INT UNSIGNED NULL DEFAULT NULL,
  `parking_id` INT UNSIGNED NOT NULL,
  `stay_type_id` INT UNSIGNED NULL DEFAULT NULL,
  `data_status` TINYINT NOT NULL DEFAULT '1' COMMENT '0=利用停止、1=利用可能、2=非表示\\n利用停止:未来で使用する可能性がない\\n非表示：論理削除（参照できる必要あり）',
  `added_flag` TINYINT(1) NOT NULL DEFAULT '0' COMMENT 'TRUE=駐車場のみを後から予約情報に追加した場合',
  `period_from` DATETIME NOT NULL COMMENT '移動前も移動後も含めた期間（時刻は\"入居時間\"）',
  `period_to` DATETIME NULL DEFAULT NULL COMMENT '移動前も移動後も含めた期間（時刻は\"入居時間\"）',
  `period_before` DATETIME NULL DEFAULT NULL COMMENT '早期退室や延長される前の日時',
  `checkin_flag` INT UNSIGNED NOT NULL DEFAULT '0',
  `checkout_flag` INT UNSIGNED NOT NULL DEFAULT '0',
  `checkout_date` DATETIME NULL DEFAULT NULL,
  `confirm_flag` TINYINT(1) NOT NULL DEFAULT '1' COMMENT 'FALSE=未定(仮予約)、TRUE=確定',
  `car_type` VARCHAR(255) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `license_plate` VARCHAR(255) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NULL DEFAULT NULL,
  `note` VARCHAR(256) CHARACTER SET 'utf8mb4' COLLATE 'utf8mb4_unicode_ci' NOT NULL,
  `booking_unit_price` INT NOT NULL,
  `adjustment_unit_price` INT NOT NULL COMMENT 'CPなどで安くなっている場合、その単価を記載',
  `created_at` TIMESTAMP NULL DEFAULT NULL,
  `updated_at` TIMESTAMP NULL DEFAULT NULL,
  `deleted_at` TIMESTAMP NULL DEFAULT NULL,
  `created_staff_id` INT UNSIGNED NOT NULL,
  `updated_staff_id` INT UNSIGNED NULL DEFAULT NULL,
  `deleted_staff_id` INT UNSIGNED NULL DEFAULT NULL,
