  INDEX `trunkroom_reserves_client_id_foreign` (`client_id` ASC) VISIBLE,
  INDEX `trunkroom_reserves_stay_type_id_foreign` (`stay_type_id` ASC) VISIBLE,
  INDEX `trunkroom_reserves_trunkroom_id_foreign` (`trunkroom_id` ASC) VISIBLE,
  INDEX `trunkroom_reserves_created_staff_id_foreign` (`created_staff_id` ASC) VISIBLE,
  INDEX `trunkroom_reserves_updated_staff_id_foreign` (`updated_staff_id` ASC) VISIBLE,
  INDEX `trunkroom_reserves_deleted_staff_id_foreign` (`deleted_staff_id` ASC) VISIBLE,
